const trigger = $('Telegram Trigger').first().json;
const photoBinary = $binary.data;
const mime = photoBinary.mimeType || 'image/jpeg';
const base64 = photoBinary.data;

return [{
  json: {
    chat_id: trigger.message.chat.id,
    user_id: trigger.message.from.id,
    username: trigger.message.from.username || '',
    photo_mime: mime,
    image_data_url: `data:${mime};base64,${base64}`,
    openai_payload: {
      model: 'gpt-4.1-mini',
      input: [
        {
          role: 'system',
          content: [
            {
              type: 'input_text',
              text: 'You are a strict food label analyst. Read the package image and return valid JSON only.'
            }
          ]
        },
        {
          role: 'user',
          content: [
            {
              type: 'input_text',
              text: `Analyze this product label image. Extract the product name, brand name if visible, ingredients, nutrition information, and then judge whether it looks Healthy, Moderate, Poor, or Unclear. Do not invent anything not visible. Return JSON only with this exact schema:\n{\n  \"product_name\": \"\",\n  \"brand_name\": \"\",\n  \"ingredients_text\": \"\",\n  \"nutrition_text\": \"\",\n  \"health_score\": 0,\n  \"verdict\": \"Healthy|Moderate|Poor|Unclear\",\n  \"summary\": \"\",\n  \"good_points\": [\"\"],\n  \"concerning_points\": [\"\"],\n  \"chart_data\": {\n    \"beneficial\": 0,\n    \"neutral\": 0,\n    \"concerning\": 0\n  },\n  \"telegram_message\": \"\"\n}\nRules: health_score must be 0-100. chart_data must total exactly 100.`
            },
            {
              type: 'input_image',
              image_url: `data:${mime};base64,${base64}`
            }
          ]
        }
      ]
    }
  },
  binary: $binary
}];

const prior = $('Code - Build OpenAI Payload').first().json;
const resp = $json;

function tryParse(str) {
  try { return JSON.parse(str); } catch (e) { return null; }
}

let rawText = '';

if (typeof resp.output_text === 'string' && resp.output_text.trim()) {
  rawText = resp.output_text.trim();
} else if (Array.isArray(resp.output)) {
  for (const item of resp.output) {
    if (Array.isArray(item.content)) {
      for (const c of item.content) {
        if (typeof c.text === 'string' && c.text.trim()) {
          rawText = c.text.trim();
          break;
        }
      }
    }
    if (rawText) break;
  }
}

let parsed = tryParse(rawText);
if (!parsed && rawText.startsWith('```')) {
  parsed = tryParse(rawText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/, '').trim());
}

if (!parsed) {
  parsed = {
    product_name: '',
    brand_name: '',
    ingredients_text: '',
    nutrition_text: '',
    health_score: 0,
    verdict: 'Unclear',
    summary: 'I could not parse the model response cleanly. Please send a sharper image.',
    good_points: [],
    concerning_points: [],
    chart_data: { beneficial: 0, neutral: 0, concerning: 100 },
    telegram_message: 'I could not read this label clearly. Please send a sharper image of the ingredients or nutrition panel.'
  };
}

parsed.product_name = (parsed.product_name || '').trim();
parsed.brand_name = (parsed.brand_name || '').trim();
parsed.ingredients_text = parsed.ingredients_text || '';
parsed.nutrition_text = parsed.nutrition_text || '';
parsed.health_score = Math.max(0, Math.min(100, Number(parsed.health_score || 0)));
parsed.verdict = parsed.verdict || 'Unclear';
parsed.summary = parsed.summary || '';
parsed.good_points = Array.isArray(parsed.good_points) ? parsed.good_points : [];
parsed.concerning_points = Array.isArray(parsed.concerning_points) ? parsed.concerning_points : [];

let beneficial = Number(parsed.chart_data?.beneficial || 0);
let neutral = Number(parsed.chart_data?.neutral || 0);
let concerning = Number(parsed.chart_data?.concerning || 0);
beneficial = Math.max(0, Math.min(100, beneficial));
neutral = Math.max(0, Math.min(100, neutral));
concerning = Math.max(0, Math.min(100, concerning));
let total = beneficial + neutral + concerning;
if (total !== 100) {
  if (total === 0) {
    beneficial = 0; neutral = 0; concerning = 100;
  } else {
    const scale = 100 / total;
    beneficial = Math.round(beneficial * scale);
    neutral = Math.round(neutral * scale);
    concerning = 100 - beneficial - neutral;
  }
}

const telegramText = parsed.telegram_message && parsed.telegram_message.trim()
  ? parsed.telegram_message.trim()
  : `*${parsed.product_name || 'Product analysis'}*\n\nVerdict: ${parsed.verdict}\nScore: ${parsed.health_score}/100\n\n${parsed.summary || 'No clear summary available.'}\n\nConcerning points:\n- ${parsed.concerning_points.length ? parsed.concerning_points.join('\n- ') : 'None clearly detected'}\n\nGood points:\n- ${parsed.good_points.length ? parsed.good_points.join('\n- ') : 'None clearly detected'}`;

const chartConfig = {
  type: 'pie',
  data: {
    labels: ['Beneficial', 'Neutral', 'Concerning'],
    datasets: [{ data: [beneficial, neutral, concerning] }]
  },
  options: {
    plugins: {
      legend: { position: 'bottom' },
      title: { display: true, text: `${parsed.product_name || 'Product'} Ingredient Profile` }
    }
  }
};

const chartUrl = 'https://quickchart.io/chart?width=800&height=500&format=png&c=' + encodeURIComponent(JSON.stringify(chartConfig));

return [{
  json: {
    chat_id: prior.chat_id,
    user_id: prior.user_id,
    username: prior.username,
    product_name_key: (parsed.product_name || '').trim().toLowerCase(),
    analysis: {
      product_name: parsed.product_name || '',
      brand_name: parsed.brand_name || '',
      ingredients_text: parsed.ingredients_text || '',
      nutrition_text: parsed.nutrition_text || '',
      health_score: parsed.health_score,
      verdict: parsed.verdict,
      summary: parsed.summary,
      good_points: parsed.good_points,
      concerning_points: parsed.concerning_points,
      chart_data: {
        beneficial,
        neutral,
        concerning
      }
    },
    telegram_text: telegramText,
    chart_url: chartUrl
  }
}];
